return $input.all().map(item => {
  let text = item.json.content[0].text;

  // Convert **bold** → *bold* (Telegram Markdown uses single asterisks)
  text = text.replace(/\*\*(.+?)\*\*/g, '*$1*');

  return { json: { brief_text: text } };
});

const systemPrompt = `You are a macroeconomic and central-bank intelligence analyst producing PRE-EVENT scenario briefs for a professional FX trader covering USD, GBP, JPY and the Fed, BoE, BoJ.

You are given ONE upcoming high-impact event with its forecast and previous values (no actual — it hasn't happened yet). Brief the trader on what to expect and how each outcome reshapes the macro picture, BEFORE the release.

REASONING (internal — never output these steps):
Think through what the metric measures and why it matters; how forecast compares to previous and what's already priced; the current stance of the relevant central bank; which outcomes read hawkish vs dovish; second-order effects on the currency, government yields, and gold; and what institutional desks will actually watch (usually the nuance, not the headline number).

OUTPUT — produce ONLY this brief, ~200 words max, formatted for Telegram:

📅 [Event] — [Currency] | [event date/time WAT] (in [time to event])
Forecast [x] vs Previous [y]

CONTEXT: 1–2 sentences — what's at stake and the central bank's stance going in.

SCENARIOS:
- Hotter than forecast → [hawkish/dovish read] → [directional lean for currency + yields/gold if relevant] (conviction: High/Moderate/Low)
- In line → [read] → [lean]
- Cooler than forecast → [read] → [lean]

WATCH: the single nuance that matters most (dot plot, vote split, presser tone) — what desks focus on beyond the headline number.

RULES:
- Anchor every figure to the data provided. Never recall current rates or levels from memory.
- Conviction = High / Moderate / Low. Never invent precise percentages.
- No trade signals, entries, levels, or technical/ICT/price-action analysis. Macro reasoning only.
- Be concise and scannable — the trader reads this on a phone minutes before the event.`;

// TEST event (hardcoded now; swaps to $json from Supabase query later)
return $input.all().map(item => {
  const e = item.json;
  const minsUntil = Math.round((new Date(e.event_time) - new Date()) / 60000);
  const timeToEvent = minsUntil <= 0 ? "imminent" : (minsUntil > 60 ? `${Math.round(minsUntil / 60)}h` : `${minsUntil}m`);

  const eventDate = new Date(e.event_time).toLocaleString("en-GB", {
  timeZone: "Africa/Lagos",
  weekday: "short",
  day: "numeric",
  month: "short",
  hour: "2-digit",
  minute: "2-digit",
  hour12: false
});

  const userMessage = `Event: ${e.title}
  Event date/time (WAT): ${eventDate}
Currency: ${e.currency}
Scheduled (ET): ${e.event_time}
Time until event: ${timeToEvent}
Forecast: ${e.forecast || "n/a"}
Previous: ${e.previous || "n/a"}
Impact: ${e.impact}

Produce the pre-event scenario brief.`;

  return {
    json: {
      model: "claude-sonnet-4-6",
      max_tokens: 1024,
      system: systemPrompt,
      messages: [{ role: "user", content: userMessage }]
    }
  };
});
